# --- 1. Model Download and Loading from URL ---
# PyTorch's `torch.load` function does not directly accept URLs.
# Instead, you typically download the state_dict (model weights) from a URL
# and then load it into a model architecture.
# `torch.hub.load_state_dict_from_url` is the recommended way to handle this,
# as it downloads the file and then loads it using `torch.load` internally.

def load_model_from_url_and_architecture(model_name, url, num_classes, checkpoint_dir):
    """
    Downloads a model state_dict from a URL, loads it into the model architecture,
    and modifies the final layer for the specified number of classes.
    """
    print(f"Downloading state_dict for {model_name} from URL: {url}")
    os.makedirs(checkpoint_dir, exist_ok=True)
    
    # torch.hub.load_state_dict_from_url handles the download and internal torch.load
    # It also caches the downloaded file, so subsequent calls are faster.
    state_dict = torch.hub.load_state_dict_from_url(
        url,
        model_dir=checkpoint_dir,
        map_location='cpu' # Load to CPU first, then move to GPU if available
    )

    print(f"State_dict downloaded. Initializing {model_name} architecture and loading state_dict.")
    
    # Initialize the model architecture (pretrained=False as we load weights manually)
    if model_name == "resnet18":
        model = torchvision.models.resnet18(pretrained=False)
        # Load the downloaded state_dict
        model.load_state_dict(state_dict)
        # Modify the final fully connected layer for custom number of classes
        num_ftrs = model.fc.in_features
        model.fc = nn.Linear(num_ftrs, num_classes)
    elif model_name == "alexnet":
        model = torchvision.models.alexnet(pretrained=False)
        model.load_state_dict(state_dict)
        num_ftrs = model.classifier[6].in_features
        model.classifier[6] = nn.Linear(num_ftrs, num_classes)
    elif model_name == "vgg16":
        model = torchvision.models.vgg16(pretrained=False)
        model.load_state_dict(state_dict)
        num_ftrs = model.classifier[6].in_features
        model.classifier[6] = nn.Linear(num_ftrs, num_classes)
    else:
        raise ValueError(f"Model '{model_name}' not supported by this script for URL loading or modification.")
        
    print(f"Model '{model_name}' architecture loaded with downloaded state_dict and final layer modified.")
    return model

